const STORAGE_KEY = "notepad-content";

let _beforeUnloadHandler = null;

export function loadContent() {
    return localStorage.getItem(STORAGE_KEY) ?? "";
}

export function saveContent(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function clearContent() {
    localStorage.removeItem(STORAGE_KEY);
}

export function enableBeforeUnload() {
    if (_beforeUnloadHandler) return;
    _beforeUnloadHandler = (e) => {
        e.preventDefault();
    };
    window.addEventListener("beforeunload", _beforeUnloadHandler);
}

export function disableBeforeUnload() {
    if (!_beforeUnloadHandler) return;
    window.removeEventListener("beforeunload", _beforeUnloadHandler);
    _beforeUnloadHandler = null;
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-2 mb-2">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted ms-2">Last saved at @lastSavedAt</span>
    }
</div>

@code {
    private string content = "";
    private string savedContent = "";
    private string? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/Pages/Notepad.razor.js");

        content = await module.InvokeAsync<string>("loadContent");
        savedContent = content;

        autoSaveTimer = new System.Threading.Timer(
            async _ => await InvokeAsync(AutoSave),
            null,
            TimeSpan.FromSeconds(30),
            TimeSpan.FromSeconds(30));

        StateHasChanged();
    }

    private async Task AutoSave()
    {
        if (content != savedContent)
        {
            await Save();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("saveContent", content);
        savedContent = content;
        lastSavedAt = DateTime.Now.ToString("HH:mm:ss");
        await module.InvokeVoidAsync("disableBeforeUnload");
    }

    private async Task Clear()
    {
        if (module is null) return;
        content = "";
        savedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent");
        await module.InvokeVoidAsync("disableBeforeUnload");
    }

    protected override async Task OnAfterRenderAsync_TrackDirty()
    {
        // Intentionally left empty; dirty tracking is in the property setter approach below.
    }

    private async Task UpdateBeforeUnload()
    {
        if (module is null) return;
        if (content != savedContent)
            await module.InvokeVoidAsync("enableBeforeUnload");
        else
            await module.InvokeVoidAsync("disableBeforeUnload");
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
            await autoSaveTimer.DisposeAsync();

        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("disableBeforeUnload");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
    }
}

